}

.inbox-item {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--space-sm);
  padding-block: var(--space-sm);
  padding-inline: var(--space-sm);
  border-block-end: 1px solid var(--color-border);
}

.inbox-item:first-child {
  border-block-start: 1px solid var(--color-border);
}

.inbox-item__title {
  flex: 1;
  min-inline-size: 0;
  overflow-wrap: break-word;
}

.inbox-item__actions {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  flex-shrink: 0;
}

.inbox-item__clarify {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
}

.inbox-item__context-label {
  font-size: var(--font-size-xs);
  color: var(--color-fg-muted);
}

.inbox-item__context-select {
  font-size: var(--font-size-sm);
  padding: var(--space-xs);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  background: var(--color-bg);
  color: var(--color-fg);
}

.inbox-item__clarify-button {
  background: var(--color-primary);
  color: var(--color-bg);
  border: none;
  padding: var(--space-xs) var(--space-sm);
  cursor: pointer;
  font-size: var(--font-size-sm);
  border-radius: var(--radius-sm);
  font-weight: var(--font-medium);
}

.inbox-item__clarify-button:hover {
  opacity: 0.9;
}

.inbox-item__delete {
  flex-shrink: 0;
}

.inbox-item__delete-button {
  background: none;
  border: none;
  padding: var(--space-xs);
  cursor: pointer;
  color: var(--color-fg-muted);
  font-size: var(--font-size-sm);
  border-radius: var(--radius-sm);
}

.inbox-item__delete-button:hover {
  background: none;
  color: var(--color-danger);
}

/* Inbox empty state */
.inbox__empty-state {
  color: var(--color-fg-muted);
  font-size: var(--font-size-sm);
  text-align: center;
  padding-block: var(--space-xl);
}

/* ---- Contexts ---- */
.contexts {
  padding-block-start: var(--space-lg);
}

.contexts h1 {
  margin-block-end: var(--space-sm);
}

